const items = $input.all();
const results = [];

const F = {
  name: 'fldBhCi2Mmn2DrjHj',
  phone: 'flddIaNdaLRS3Cqj1',
  email: 'fldrk8muHfcF3Pbgq',
  source: 'fldhTGJfmH3bSIRNi',
  caseType: 'fldFvHcaJFi5avKIJ',
  qualification: 'fldB2X3rDt70i3IaM',
  status: 'fldvigglUZz1WCh9w',
  sourcePage: 'fld32SWWh3EpUz3su',
  sourceUrl: 'fldZvIeS670c9k2FC',
  notes: 'fldRhukW6qHMGPtl7',
  assignedTo: 'fldrOeav9AFscL0eo',
  createdAt: 'fldQ2B6JLQmit8CQl',
};

for (const item of items) {
  const fields = item.json.fields || item.json;
  const get = (id, fallback) => fields[id] || fields[fallback] || '';

  const name = get(F.name, 'Imię') || 'Brak imienia';
  const phone = get(F.phone, 'Telefon') || 'Brak';
  const email = get(F.email, 'Email');
  const caseType = get(F.caseType, 'Typ zdarzenia') || 'Nieokreślony';
  const qualification = get(F.qualification, 'Kwalifikacja');
  const source = get(F.source, 'Kanał źródłowy');
  const sourcePage = get(F.sourcePage, 'Źródło strony');
  const notes = get(F.notes, 'Notatki');
  const createdAt = get(F.createdAt, 'Data utworzenia') || new Date().toISOString().split('T')[0];

  // Formatuj datę
  let dateStr = createdAt;
  try { dateStr = new Date(createdAt).toLocaleString('pl-PL', { dateStyle: 'long', timeStyle: 'short' }); } catch(e) {}

  // Wyczyść notatki z session ID i sformatuj jako podsumowanie
  let summary = notes;
  if (summary) {
    summary = summary.replace(/\[session:[^\]]+\]/g, '').trim();
    summary = summary.replace(/\n/g, '<br>');
  }

  const subject = `\uD83D\uDD14 Nowy lead: ${name} | ${caseType}`;

  // Buduj HTML
  let rows = '';
  const addRow = (label, val) => { if (val && val !== 'Brak') rows += `<tr><td style=\"padding:6px 12px 6px 0;color:#6b7280;white-space:nowrap;vertical-align:top;\">${label}</td><td style=\"padding:6px 0;color:#1a1a2e;font-weight:500;\">${val}</td></tr>`; };

  addRow('\uD83D\uDC64 Imię', name);
  addRow('\uD83D\uDCDE Telefon', phone);
  addRow('\u2709\uFE0F Email', email);
  addRow('\uD83D\uDCC1 Typ sprawy', caseType);
  addRow('\uD83D\uDD25 Kwalifikacja', qualification);
  addRow('\uD83D\uDCCD Źródło', [source, sourcePage].filter(Boolean).join(' — '));
  addRow('\uD83D\uDCC5 Data', dateStr);

  const WEBHOOK_BASE = 'https://n8n.kaban.click/webhook/szkody-lead-action';
  const recordId = item.json.id || '';

  const btnStyle = 'display:inline-block;padding:10px 18px;margin:4px;border-radius:6px;text-decoration:none;font-weight:600;font-size:13px;';
  const actions = recordId ? `<div style=\"margin-top:20px;padding-top:16px;border-top:2px solid #e5e7eb;text-align:center;\">`
    + `<div style=\"color:#6b7280;font-size:12px;margin-bottom:8px;\">AKCJE</div>`
    + `<a href=\"${WEBHOOK_BASE}?id=${recordId}&action=contacted\" style=\"${btnStyle}background:#1a6b3c;color:white;\">\u2705 Zadzwoni\u0142em</a>`
    + `<a href=\"${WEBHOOK_BASE}?id=${recordId}&action=no_answer\" style=\"${btnStyle}background:#ef4444;color:white;\">\u274C Nie odbiera</a>`
    + `<a href=\"${WEBHOOK_BASE}?id=${recordId}&action=followup\" style=\"${btnStyle}background:#f59e0b;color:white;\">\uD83D\uDCC5 Follow-up jutro</a>`
    + `</div>` : '';

  const body = `<div style=\"font-family:'Segoe UI',Arial,sans-serif;max-width:560px;margin:0 auto;\">`
    + `<div style=\"background:#1a6b3c;color:white;padding:16px 20px;border-radius:8px 8px 0 0;\"><h2 style=\"margin:0;font-size:18px;\">\uD83D\uDD14 Nowy lead ze strony</h2></div>`
    + `<div style=\"border:1px solid #e5e7eb;border-top:none;border-radius:0 0 8px 8px;padding:20px;\">`
    + `<table style=\"width:100%;border-collapse:collapse;font-size:14px;\">${rows}</table>`
    + (summary ? `<div style=\"margin-top:16px;padding:12px 16px;background:#f5f5f5;border-radius:6px;border-left:4px solid #1a6b3c;\"><div style=\"font-weight:600;color:#1a1a2e;margin-bottom:6px;\">\uD83D\uDCDD Podsumowanie rozmowy:</div><div style=\"color:#374151;font-size:13px;line-height:1.5;\">${summary}</div></div>` : '')
    + actions
    + `</div></div>`;

  const recipientEmail = 'piotrtokeny@gmail.com';
  results.push({ json: { subject, body, recipientEmail } });
}

return results;
